292	    /// Finds the first timeWindow metric matching the given name, or fails the test.
293	    private func requireTimeWindowMetric(
294	        named name: String,
295	        in metrics: [UsageMetric],
296	        sourceLocation: SourceLocation = #_sourceLocation
297	    ) -> (name: String, resetAt: ISODate, duration: DurationMinutes, pct: UsagePercent)? {
298	        guard let metric = metrics.first(where: {
299	            if case .timeWindow(let n, _, _, _) = $0 { return n == name }
300	            return false
301	        }) else {
302	            Issue.record("Expected timeWindow metric named '\(name)'", sourceLocation: sourceLocation)
303	            return nil
304	        }
305	        if case .timeWindow(let n, let r, let d, let p) = metric {
306	            return (name: n, resetAt: r, duration: d, pct: p)
307	        }
308	        return nil
309	    }
